// AUTO-GENERATED by workflow-poc agent
import { test, expect } from '@playwright/test';

describe('Logout Functionality', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('http://localhost:3000');
  });

  test('TC: Logout successfully from hamburger menu after login', async ({ page }) => {
    // Login
    await page.fill('input[name="email"]', 'test@example.com');
    await page.fill('input[name="password"]', 'password123');
    await page.click('button:has-text("Login")');
    await page.waitForURL('**/dashboard');

    // Open hamburger menu
    await page.click('button[aria-label="hamburger menu"]');
    
    // Click logout
    await page.click('a:has-text("Logout")');
    
    // Verify logout success
    await page.waitForURL('**/login');
    await expect(page.locator('text=Login')).toBeVisible();
  });

  test('TC: Verify login page displays after logout', async ({ page }) => {
    // Login
    await page.fill('input[name="email"]', 'test@example.com');
    await page.fill('input[name="password"]', 'password123');
    await page.click('button:has-text("Login")');
    await page.waitForURL('**/dashboard');

    // Logout
    await page.click('button[aria-label="hamburger menu"]');
    await page.click('a:has-text("Logout")');

    // Verify login page displays
    await expect(page.locator('h1:has-text("Login")')).toBeVisible();
    await expect(page.locator('input[name="email"]')).toBeVisible();
    await expect(page.locator('input[name="password"]')).toBeVisible();
  });

  test('TC: Cannot access protected pages after logout via back button', async ({ page }) => {
    // Login
    await page.fill('input[name="email"]', 'test@example.com');
    await page.fill('input[name="password"]', 'password123');
    await page.click('button:has-text("Login")');
    await page.waitForURL('**/dashboard');

    // Logout
    await page.click('button[aria-label="hamburger menu"]');
    await page.click('a:has-text("Logout")');
    await page.waitForURL('**/login');

    // Try to go back
    await page.goBack();

    // Verify redirected to login
    await expect(page).toHaveURL('**/login');
    await expect(page.locator('h1:has-text("Login")')).toBeVisible();
  });

  test('TC: Logout with valid session invalidates user credentials', async ({ page }) => {
    // Login
    await page.fill('input[name="email"]', 'test@example.com');
    await page.fill('input[name="password"]', 'password123');
    await page.click('button:has-text("Login")');
    await page.waitForURL('**/dashboard');

    // Logout
    await page.click('button[aria-label="hamburger menu"]');
    await page.click('a:has-text("Logout")');
    await page.waitForURL('**/login');

    // Try to access dashboard directly
    await page.goto('http://localhost:3000/dashboard');

    // Verify redirected to login
    await expect(page).toHaveURL('**/login');
  });

  test('TC: Logout fails gracefully on network error', async ({ page, context }) => {
    // Login
    await page.fill('input[name="email"]', 'test@example.com');
    await page.fill('input[name="password"]', 'password123');
    await page.click('button:has-text("Login")');
    await page.waitForURL('**/dashboard');

    // Simulate network offline
    await context.setOffline(true);

    // Attempt logout
    await page.click('button[aria-label="hamburger menu"]');
    await page.click('a:has-text("Logout")');

    // Verify error message or graceful handling
    await expect(page.locator('text=Error|Network error|Connection failed')).toBeVisible();

    // Restore connection
    await context.setOffline(false);
  });

  test('TC: Logout clears session cookies and tokens', async ({ page, context }) => {
    // Login
    await page.fill('input[name="email"]', 'test@example.com');
    await page.fill('input[name="password"]', 'password123');
    await page.click('button:has-text("Login")');
    await page.waitForURL('**/dashboard');

    // Get cookies before logout
    const cookiesBefore = await context.cookies();
    expect(cookiesBefore.some(c => c.name === 'authToken')).toBeTruthy();

    // Logout
    await page.click('button[aria-label="hamburger menu"]');
    await page.click('a:has-text("Logout")');
    await page.waitForURL('**/login');

    // Get cookies after logout
    const cookiesAfter = await context.cookies();
    const authToken = cookiesAfter.find(c => c.name === 'authToken');
    
    // Verify authToken is cleared
    expect(authToken).toBeUndefined();
  });

  test('TC: Logout behavior consistent across multiple browser tabs', async ({ browser }) => {
    // Open first tab and login
    const context = await browser.newContext();
    const page1 = await context.newPage();
    await page1.goto('http://localhost:3000');
    await page1.fill('input[name="email"]', 'test@example.com');
    await page1.fill('input[name="password"]', 'password123');
    await page1.click('button:has-text("Login")');
    await page1.waitForURL('**/dashboard');

    // Open second tab
    const page2 = await context.newPage();
    await page2.goto('http://localhost:3000/dashboard');
    await page2.waitForURL('**/dashboard');

    // Logout from first tab
    await page1.click('button[aria-label="hamburger menu"]');
    await page1.click('a:has-text("Logout")');
    await page1.waitForURL('**/login');

    // Verify second tab is also logged out
    await page2.reload();
    await expect(page2).toHaveURL('**/login');

    await context.close();
  });

  test('TC: Logout during pending form submission', async ({ page }) => {
    // Login
    await page.fill('input[name="email"]', 'test@example.com');
    await page.fill('input[name="password"]', 'password123');
    await page.click('button:has-text("Login")');
    await page.waitForURL('**/dashboard');

    // Navigate to a page with form
    await page.goto('http://localhost:3000/settings');

    // Start form submission but don't wait
    await page.fill('input[name="username"]', 'newusername');
    await page.click('button:has-text("Save")');

    // Logout immediately
    await page.click('button[aria-label="hamburger menu"]');
    await page.click('a:has-text("Logout")');

    // Verify logout completes
    await page.waitForURL('**/login');
    await expect(page.locator('h1:has-text("Login")')).toBeVisible();
  });

  test('TC: Logout option visible only when user is authenticated', async ({ page }) => {
    // Verify logout is not visible before login
    await page.goto('http://localhost:3000');
    await page.click('button[aria-label="hamburger menu"]');
    await expect(page.locator('a:has-text("Logout")')).not.toBeVisible();
    await page.keyboard.press('Escape');

    // Login
    await page.fill('input[name="email"]', 'test@example.com');
    await page.fill('input[name="password"]', 'password123');
    await page.click('button:has-text("Login")');
    await page.waitForURL('**/dashboard');

    // Verify logout is visible after login
    await page.click('button[aria-label="hamburger menu"]');
    await expect(page.locator('a:has-text("Logout")')).toBeVisible();
  });

  test('TC: Session invalidation prevents page refresh after logout', async ({ page }) => {
    // Login
    await page.fill('input[name="email"]', 'test@example.com');
    await page.fill('input[name="password"]', 'password123');
    await page.click('button:has-text("Login")');
    await page.waitForURL('**/dashboard');

    // Logout
    await page.click('button[aria-label="hamburger menu"]');
    await page.click('a:has-text("Logout")');
    await page.waitForURL('**/login');

    // Try to refresh dashboard
    await page.goto('http://localhost:3000/dashboard');

    // Verify session is invalid and redirects to login
    await expect(page).toHaveURL('**/login');
    await expect(page.locator('h1:has-text("Login")')).toBeVisible();
  });
});
